":\"010ef399-60bb-4a2b-9a0e-bd05dc924528\",\"data\":{\"name\":\"native.join\",\"inputs\":[{\"name\":\"maintable\",\"type\":\"Table\",\"title\":\"Main table\",\"description\":\"Main table\"},{\"name\":\"secondarytable\",\"type\":\"Table\",\"title\":\"Secondary table\",\"description\":\"Secondary table\"},{\"name\":\"maincolumn\",\"type\":\"Column\",\"title\":\"Column in main table\",\"parent\":\"maintable\",\"dataType\":[\"boolean\",\"date\",\"datetime\",\"time\",\"timestamp\",\"number\",\"string\"],\"description\":\"Column in main table\",\"value\":\"store_id\"},{\"name\":\"secondarycolumn\",\"type\":\"Column\",\"title\":\"Column in secondary table\",\"parent\":\"secondarytable\",\"dataType\":[\"boolean\",\"date\",\"datetime\",\"time\",\"timestamp\",\"number\",\"string\"],\"description\":\"Column in secondary table\",\"value\":\"store_id\"},{\"name\":\"jointype\",\"type\":\"Selection\",\"title\":\"Join type\",\"options\":[\"Inner\",\"Left\",\"Right\",\"Full outer\"],\"default\":\"Inner\",\"description\":\"Join type\",\"value\":\"Inner\"},{\"name\":\"optimizationcol\"}],\"version\":\"1.1\",\"label\":\"Join\"},\"type\":\"generic\",\"width\":64,\"height\":64,\"zIndex\":2,\"dragging\":false,\"position\":{\"x\":1760,\"y\":400},\"selected\":false,\"positionAbsolute\":{\"x\":1760,\"y\":400}},{\"id\":\"edc26a44-32d3-4c4f-8a10-9a732dfa7cf2\",\"data\":{\"name\":\"Note\",\"color\":\"#FE88B1\",\"genAi\":false,\"label\":\"\",\"width\":480,\"height\":224,\"inputs\":[],\"markdown\":\"---\\nlabel: Retail\\n---\\n## Estimate population around top performant retail stores 🛒\\n \\nThis workflow example filters out the top retail stores that belong to a specific category and computes the population living around them.\"},\"type\":\"note\",\"width\":480,\"height\":224,\"zIndex\":-1,\"dragging\":false,\"position\":{\"x\":176,\"y\":-48},\"selected\":false,\"positionAbsolute\":{\"x\":176,\"y\":-48}},{\"id\":\"095a5e71-b26f-47e9-b2c8-4c8bd7555fbf\",\"data\":{\"name\":\"Note\",\"color\":\"#F6CF71\",\"genAi\":false,\"label\":\"\",\"width\":255.991,\"height\":367.993,\"inputs\":[],\"markdown\":\"---\\nlabel: Data source\\n---\\n## Store locations in Colorado\\n\"},\"type\":\"note\",\"width\":256,\"height\":368,\"zIndex\":-1,\"dragging\":false,\"position\":{\"x\":176,\"y\":192},\"selected\":false,\"positionAbsolute\":{\"x\":176,\"y\":192}},{\"id\":\"095a5e71-b26f-47e9-b2c8-4c8bd7555fbf-1697204190336\",\"data\":{\"name\":\"Note\",\"color\":\"#9EB9F3\",\"genAi\":false,\"label\":\"\",\"width\":479.991,\"height\":367.993,\"inputs\":[],\"markdown\":\"---\\nlabel: Data preparation\\n---\\n## Filtering the top 100 Supermarkets generating more revenue\\n\\nOut of the different store types, we will filter out and keep only the Supermarkets. Then, we will rank the different supermarkets based on their revenue and keep only the top 100.\"},\"type\":\"note\",\"width\":480,\"height\":368,\"zIndex\":-1,\"dragging\":false,\"position\":{\"x\":448,\"y\":192},\"selected\":false,\"positionAbsolute\":{\"x\":448,\"y\":192}},{\"id\":\"b53391c8-ac56-4cc9-b665-1037e7553c27\",\"data\":{\"name\":\"Note\",\"color\":\"#8BE0A4\",\"genAi\":false,\"label\":\"\",\"width\":271.98699999999997,\"height\":368,\"inputs\":[],\"markdown\":\"---\\nlabel: Analysis\\n---\\n## Computing trade areas\\nIn this step we compute the 10-min car driving isolines around each store. We will consider those as their trade areas.\"},\"type\":\"note\",\"width\":272,\"height\":368,\"zIndex\":-1,\"dragging\":false,\"position\":{\"x\":944,\"y\":192},\"selected\":false,\"positionAbsolute\":{\"x\":944,\"y\":192}},{\"id\":\"68851ea4-efb6-44f1-a21b-f43d9901e182\",\"data\":{\"name\":\"Note\",\"color\":\"#F6CF71\",\"genAi\":false,\"label\":\"\",\"width\":511.99899999999997,\"height\":287.995,\"inputs\":[],\"markdown\":\"---\\nlabel: Data source\\n---\\n## CARTO Spatial Features - Colorado\\nIn this step we load CARTO Spatial Features that contain information such as population, urbanity, etc. for the whole USA in H3 spatial index format, filtered for the state of Colorado.\"},\"type\":\"note\",\"width\":512,\"height\":288,\"zIndex\":-1,\"dragging\":false,\"position\":{\"x\":176,\"y\":576},\"selected\":false,\"positionAbsolute\":{\"x\":176,\"y\":576}},{\"id\":\"d7afd6b6-b7d1-4da6-9f6b-37763a946e33\",\"data\":{\"name\":\"Note\",\"color\":\"#8BE0A4\",\"genAi\":false,\"label\":\"\",\"width\":639.9870000000001,\"height\":447.99899999999997,\"inputs\":[],\"markdown\":\"---\\nlabel: Analysis\\n---\\n## Aggregating population around each store\\nIn these steps we first polyfill the trade areas based on H3 spatial index. We use the H3 id to join the cells with the Spatial Features data and we aggregate the population at each store with the Group By component. Finally, we join again the data about the different stores.\"},\"type\":\"note\",\"width\":640,\"height\":448,\"zIndex\":-1,\"dragging\":false,\"position\":{\"x\":1232,\"y\":192},\"selected\":false,\"positionAbsolute\":{\"x\":1232,\"y\":192}},{\"id\":\"import_7fafa6a4_12d8_454c_9ced_7854de115889\",\"data\":{\"id\":\"carto-dw-ac-jfjjof5m.workflows_temp_ernesto_pmadmin_aa2de528.import_7fafa6a4_12d8_454c_9ced_7854de115889\",\"name\":\"ReadTable\",\"size\":1370186374,\"type\":\"table\",\"label\":\"derived_spatialfeatures_colorado_h3res8\",\"nrows\":335435,\"inputs\":[{\"name\":\"source\",\"type\":\"String\",\"title\":\"Source table\",\"value\":\"carto-dw-ac-jfjjof5m.workflows_temp_ernesto_pmadmin_aa2de528.import_7fafa6a4_12d8_454c_9ced_7854de115889\",\"description\":\"Read Table\"}],\"schema\":[{\"name\":\"h3\",\"type\":\"string\"},{\"name\":\"do_date\",\"type\":\"timestamp\"},{\"name\":\"country_iso\",\"type\":\"string\"},{\"name\":\"country_iso_a3\",\"type\":\"string\"},{\"name\":\"population\",\"type\":\"number\"},{\"name\":\"female\",\"type\":\"number\"},{\"name\":\"male\",\"type\":\"number\"},{\"name\":\"female_under_1\",\"type\":\"number\"},{\"name\":\"female_1_to_4\",\"type\":\"number\"},{\"name\":\"female_5_to_9\",\"type\":\"numb